+    arg[0] = '?'; break;
+  case (EX_EXTRA | EX_NEEDARG):
+    arg[0] = '+'; break;
+  case (EX_EXTRA | EX_NOSPC | EX_NEEDARG):
+    arg[0] = '1'; break;
+  }
+  PUT_C(*d, "nargs", CSTR_TO_ARENA_OBJ(arena, arg));
+
+  // count
+  Object obj = NIL;
+  if (argt & EX_COUNT) {
+    if (def >= 0) {
+      obj = STRING_OBJ(arena_printf(arena, "%" PRId64, def));
+    } else {
+      obj = CSTR_AS_OBJ("0");
+    }
+  }
+  PUT_C(*d, "count", obj);
+  // range
+  obj = NIL;
+  if (argt & EX_RANGE) {
+    if (argt & EX_DFLALL) {
+      obj = STATIC_CSTR_AS_OBJ("%");
+    } else if (def >= 0) {
+      obj = STRING_OBJ(arena_printf(arena, "%" PRId64, def));
+    } else {
+      obj = STATIC_CSTR_AS_OBJ(".");
